// decode_audio.c - فك ترميز صوت من FFmpeg
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp3";
    AVFormatContext *fmt_ctx = NULL;
    const AVCodec *codec = NULL;
    AVCodecContext *codec_ctx = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();
    int ret;

    // 1. فتح ملف الصوت
    if (avformat_open_input(&fmt_ctx, filename, NULL, NULL) < 0) {
        fprintf(stderr, "فشل فتح الملف\n");
        return 1;
    }

    // 2. البحث عن stream صوتي
    ret = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_AUDIO, -1, -1, 0, NULL);
    if (ret < 0) {
        fprintf(stderr, "لا يوجد stream صوتي\n");
        return 1;
    }
    int stream_idx = ret;

    // 3. إيجاد الـ decoder وفتحه
    codec = avcodec_find_decoder(fmt_ctx->streams[stream_idx]->codecpar->codec_id);
    codec_ctx = avcodec_alloc_context3(codec);
    avcodec_parameters_to_context(codec_ctx, fmt_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(codec_ctx, codec, NULL);

    printf("Codec: %s\n", codec->long_name);
    printf("Sample Rate: %d\n", codec_ctx->sample_rate);
    printf("Channels: %d\n", codec_ctx->ch_layout.nb_channels);

    // 4. قراءة packets وفك الترميز
    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(codec_ctx, pkt);
            while (avcodec_receive_frame(codec_ctx, frame) >= 0) {
                // frame->data يحتوي عينات PCM الخام الجاهزة للتشغيل
                printf("frame: samples=%d pts=%ld\n",
                       frame->nb_samples, frame->pts);
            }
        }
        av_packet_unref(pkt);
    }

    // 5. التنظيف
    av_frame_free(&frame);
    av_packet_free(&pkt);
    avcodec_free_context(&codec_ctx);
    avformat_close_input(&fmt_ctx);
    return 0;
}

